mapper.sql:
SELECT A.rownum_ rowindx , B.TOTAL_COUNT totalCount , A.TMPL_SERNO tmplSerno , A.TMPL_CL tmplCl , A.TMPL_CL_NM tmplClNm , A.TMPL_TP_NM tmplTpNm , A.TMPL_EXPL tmplExpl , A.PRVW_FILE_SERNO prvwFileSerno , A.REG_DT regDt FROM ( SELECT ROW_NUMBER() OVER (ORDER BY CTM.REG_DATE ASC) AS rownum_ , CTM.TMPL_SERNO AS TMPL_SERNO , CTM.TMPL_CL AS TMPL_CL , FN_S_COM_CD_INFO('TMCL',TCTM.MPL_CL,'') AS TMPL_CL_NM , CTM.TMPL_TP AS TMPL_TP , FN_S_COM_CD_INFO('TMTP',CTM.TMPL_TP,'') AS TMPL_TP_NM , CTM.TMPL_EXPL AS TMPL_EXPL , CTM.PRVW_FILE_SERNO AS PRVW_FILE_SERNO , DATE_FORMAT(CTM.REG_DATE, '%Y.%m.%d') AS REG_DT FROM STB_B_CONT_TMPL_MNG CTM WHERE USE_YN = 'Y'
) JOIN ( SELECT COUNT(*) TOTAL_COUNT FROM STB_B_CONT_TMPL_MNG CTM WHERE USE_YN = 'Y'
) B ON 1 = 1

mapper.select:
/* com.standard.usersupport.ContentTemplate.selectList */ SELECT TMPL_SERNO tmplSerno , FNC_CODE_NM(TMPL_CL) tmplCl , FNC_CODE_NM(TMPL_TP) tmplTp , TMPL_EXPL tmplExpl , PRVW_FILE_SERNO prvwFileSerno , DATE_FORMAT(REG_DT, '%Y.%m.%d') regDt FROM STB_B_CONT_TMPL_MNG
AND USE_YN = 'Y'
ORDER BY TMPL_SERNO DESC LIMIT #{firstRecordIndex} , #{recordCountPerPage}
